import React, {useEffect, useState} from 'react'
import styled from 'styled-components'
import {getUserProfile} from '../WebAPI'


const ProfileWrapper = styled.div `

`


const Section = styled.div `
display:flex;
margin:20px 0;
align-items:center;
`

const Bio = styled.div `
`

const Title = styled.div `
font-size:0.9rem;
letter-spacing:5px;
color:grey;
font-weight:900;
`

const Div = styled.div `
margin-left:20px;
border-radius:8px;
border:1px solid rgb(230, 230, 230);
height:30px;
width:400px;
color:grey;
padding:0 10px;
box-sizing:border-box;
&:focus {
	outline: none !important;
}
`

const Text = styled.div `
margin-left:20px;
border-radius:8px;
border:1px solid rgb(230, 230, 230);
height:60px;
width:500px;
&:focus {
	outline: none !important;
}
`

export default function MeProfile () {
	const [userProfile, setUserProfile] = useState([{}])
	const [username, setUsername] = useState()
	const [email, setEmail] = useState()
	const [bio, setBio] = useState()

	useEffect(() => {
		getUserProfile(localStorage.getItem('userId'), setUserProfile)
	},[])

	const onUsernameChange = e => {
		setUsername(e.target.value)
	}

	const onEmailChange = e => {
		setEmail(e.target.value)
	}

	const onBioChange = e => {
		setBio(e.target.value)
	}

	console.log(userProfile)

	return (
		<ProfileWrapper>
			<Section>
				<Title>USERNAME</Title>
				<Div value={username} onChange={onUsernameChange}></Div>
			</Section>
			<Section>
				<Title>EMAIL</Title>
				<Div value={email} onChange={onEmailChange}></Div>
			</Section>
			<Section>
				<Title>BIO</Title>
				<Text value={bio} onChange={onBioChange}></Text>
			</Section>
		</ProfileWrapper>
	)
}

